#start textdef showStart():#print a title and the commands    print('''Welcome to MinesweeperTo start, please enter your preferred board settings. Ex: 5x7 17%For board dimensions; min 5, max 26. For mine percentage; min 4%, max 96%. All must be integer values.You may also enter 'y' to play the default 5x5 16% board.Input 'q' 'quit' or 'exit' at any time to end the program.''')rows = 5cols = 5minePercent = 0.16solvedBoard = [[0 for _ in range(cols)] for _ in range(rows)] #full board of minesweeper numbers, mines are 11visibleBoard = [[9 for _ in range(cols)] for _ in range(rows)] #what the player sees, except 9 -> ' ' un-revealed safe tiles, 10 -> ' ' is un-revealed mines, 11 -> '💣' is revealed mines# 12 -> '🚩' flagged safe tiles, 13 -> '🚩' flagged minesfirstMove = Truegame = False #if this is false, we're listening for dimensions, if it's true we're listening for coordinates#player statswins = 0losses = 0def showBoard():    #print the board    print("---------------------------")    header = "  "    for i in range(cols):        l = chr(i+65)        header += "  " + l    print(header)    for i in range(rows):        row = f"{i + 1} "        if i < 9: #extra space for single digit numbers            row += " "        for j in range(cols):            value = visibleBoard[i][j]            if value == 9 or value == 10:                row += f"[ ]"            elif value == 11:                row += f"💣 "            elif value == 12 or value == 13:                row += f"🚩 "            else:                cell = str(value)                row += f"[{cell}]"        if cols > 10: #have the number labels on both sides if the board is wider than 10 columns                        if i < 9: #extra space for single digit numbers                row += " "            row += f" {i + 1}"        print(row)    if rows > 10: #have the letter labels on both sides if the board is longer than 10 rows        print(header)    print("---------------------------")def newBoard(row, col):    import random    safeRows = {row, row+1, row-1}    safeCols = {col, col+1, col-1}    # all possible mine positions, everything except the 3x3 box surrounding the start move    positions = [(i, j) for i in range(rows) for j in range(cols) if not (i in safeRows and j in safeCols)]    # pick 16% at random    num = round(minePercent * rows * cols)    if num > len(positions): #mine percentage is too high, the first guess won't be a 0, but it will be safe        positions = [(i, j) for i in range(rows) for j in range(cols) if (i,j) != (row, col)]    chosen = random.sample(positions, num)    # label them as mines in both tables    for i, j in chosen:        solvedBoard[i][j] = 11        visibleBoard[i][j] = 10    # put the minesweeper numbers in the solved board    for i in range(rows):        for j in range(cols):            if solvedBoard[i][j] == 11:                continue  # skip mines            # count surrounding mines            count = 0            for di in [-1, 0, 1]:                for dj in [-1, 0, 1]:                    if di == 0 and dj == 0:                        continue  # skip self                    ni, nj = i + di, j + dj                    if 0 <= ni < rows and 0 <= nj < cols:                        if solvedBoard[ni][nj] == 11:                            count += 1            solvedBoard[i][j] = count            def reveal(row, col):    if row == 100:        #this is called when the player loses: reveal all the mines, leave the rest of the board the same        for i in range(len(visibleBoard)):            for j in range(len(visibleBoard[i])):                if visibleBoard[i][j] == 10:                    visibleBoard[i][j] = 11    elif row == 101:        #this is called when the player wins: flag all the mines, leave the rest of the board the same        for i in range(len(visibleBoard)):            for j in range(len(visibleBoard[i])):                if visibleBoard[i][j] == 10:                    visibleBoard[i][j] = 13    else:        #reveal a tile        visibleBoard[row][col] = solvedBoard[row][col]        if visibleBoard[row][col] == 0:            # check and reveal adjacent tiles (auto-fill)            for dr in [-1, 0, 1]:                for dc in [-1, 0, 1]:                    if dr == 0 and dc == 0:                        continue  # skip the original cell itself                    nr, nc = row + dr, col + dc                    # Check boundaries                    if 0 <= nr < rows and 0 <= nc < cols:                        if visibleBoard[nr][nc] == 9:                            reveal(nr, nc)                            def flag(row, col):    if visibleBoard[row][col] == 9:        visibleBoard[row][col] = 12    elif visibleBoard[row][col] == 10:        visibleBoard[row][col] = 13showStart()#loopwhile True:    if game:        showBoard()        #get input    s = ''    while s == '':        s = input('>')    #allow quitting at any point    if s == "q" or s == "quit" or s == "exit":        w = f"{wins} times"        l = f"{losses} times"        if wins == 1: # so it doesnt say "won 1 times"            w = "once"        if losses == 1:            l = "once"        print(f"Thank you for playing minesweeper! You played {wins+losses} rounds, won " + w + " and lost " + l + ".")        print("Ending program...")        break    if not game:        #listen for affirmative (play with previously defined rows/cols) or dimensions        if s.lower() == "y":            #begin game            game = True            #initialize the boards, in case this is a re-play            solvedBoard = [[0 for _ in range(cols)] for _ in range(rows)]            visibleBoard = [[9 for _ in range(cols)] for _ in range(rows)]            #tell the player the controls & mine count            p = round(minePercent*100)            count = round(minePercent * rows * cols)            print(f"Settings: {cols}x{rows} {p}% | Mine Count: {count}")            print('To reveal tiles, type the coordinates. Ex: A3')            print('To flag or unflag mines, include an F afterwards. Ex: C4F')            continue        elif "x" in s and " " in s and "%" in s:            d, p = s.split(' ', 1)                            c, r = d.split('x', 1)            if c.isdigit() and r.isdigit():                if int(c) < 5 or int(r) < 5:                    print("Minimum board dimensions are 5x5, try again.")                else:                    #valid dimensions, check percentage                    if p[:-1].isdigit():                        if int(p[:-1]) > 3 and int(p[:-1]) < 97:                            minePercent = int(p[:-1]) / 100                            cols = int(c)                            rows = int(r)                            #begin game                            game = True                            #re-initialize the boards with the new dimensions                            solvedBoard = [[0 for _ in range(cols)] for _ in range(rows)]                            visibleBoard = [[9 for _ in range(cols)] for _ in range(rows)]                            #tell the player the controls & mine count                            p = round(minePercent*100)                            count = round(minePercent * rows * cols)                            print(f"Settings: {cols}x{rows} {p}% | Mine Count: {count}")                            print('To reveal tiles, type the coordinates. Ex: A3')                            print('To flag or unflag mines, include an F afterwards. Ex: C4F')                            continue                        else:                            print("Mine percentage must be between 4% and 96%, try again.")                    else:                        print("Invalid mine percentage, try again.")            else:                print("Invalid board settings, try again.")        else:            print("Invalid board settings, try again.")    else:        #if the last character is an F, then it is flag        if s[-1].lower() == "f":            #you can't start with a flag            if firstMove:               print("Try revealing a tile first. Your first guess is always safe!")             else:                #just remove the f entirely                s = s[:-1]                if s[1:].isdigit(): #make sure that without the first char it is a number                    row = int(s[1:]) - 1                    col = ord(s[0].lower()) - ord('a')                    if row >= rows or col >= cols or s[1] == "0":                        print("Those coordinates are out of range, try again.")                     else:                        # update the board                        row = int(s[1:]) - 1                        col = ord(s[0].lower()) - ord('a')                        flag(row, col)                else:                    print("Invalid input, try again.")         else:            if s[1:].isdigit(): #make sure that without the first char it is a number                row = int(s[1:]) - 1                col = ord(s[0].lower()) - ord('a')                if row >= rows or col >= cols or s[1] == "0":                    print("Those coordinates are out of range, try again.")                 else:                    if firstMove:                            # generate a board                            row = int(s[1:]) - 1                            col = ord(s[0].lower()) - ord('a')                            newBoard(row, col)                            reveal(row, col)                            firstMove = False                    else:                        # update the board                        row = int(s[1:]) - 1                        col = ord(s[0].lower()) - ord('a')                        reveal(row, col)            else:                print("Invalid input, try again.")        #win logic        win = True        loss = False        for row in visibleBoard:            if 11 in row: #11's are revealed mines, you exploded!                win = False                loss = True                break        for row in visibleBoard:            if 9 in row or 12 in row: #9's and 12's are unrevealed safe tiles, if there are none then we won                win = False                break        if win:            wins += 1            reveal(101, 0)            showBoard()            print('YOU WIN!')            p = round(minePercent*100)            print(f"To play again, input new settings or 'y' to use the same: {cols}x{rows} {p}%")            #reset            firstMove = True            game = False        #loss logic        elif loss:            losses += 1            reveal(100, 0)            showBoard()            print('GAME OVER!')            p = round(minePercent*100)            print(f"To play again, input new settings or 'y' to use the same: {cols}x{rows} {p}%")            #reset            firstMove = True            game = False